1	import axios from 'axios';
2	
3	const api = axios.create({
4	  baseURL: '/api',
5	  withCredentials: true,
6	});
7	
8	// Request interceptor: inject CSRF token from cookie
9	api.interceptors.request.use((config) => {
10	  const csrfToken = document.cookie
11	    .split('; ')
12	    .find((row) => row.startsWith('csrf_token='))
13	    ?.split('=')[1];
14	
15	  if (csrfToken && config.method !== 'get') {
16	    config.headers['X-CSRF-Token'] = csrfToken;
17	  }
18	  return config;
19	});
20	
21	// Response interceptor: handle 401 with silent refresh
22	let isRefreshing = false;
23	let failedQueue: Array<{
24	  resolve: (value?: unknown) => void;
25	  reject: (reason?: unknown) => void;
26	}> = [];
27	
28	const processQueue = (error: unknown | null) => {
29	  failedQueue.forEach((prom) => {
30	    if (error) {
31	      prom.reject(error);
32	    } else {
33	      prom.resolve();
34	    }
35	  });
36	  failedQueue = [];
37	};
38	
39	api.interceptors.response.use(
40	  (response) => response,
41	  async (error) => {
42	    const originalRequest = error.config;
43	
44	    if (error.response?.status === 401 && !originalRequest._retry) {
45	      if (originalRequest.url === '/auth/refresh') {
46	        window.location.href = '/login';
47	        return Promise.reject(error);
48	      }
49	
50	      if (isRefreshing) {
51	        return new Promise((resolve, reject) => {
52	          failedQueue.push({ resolve, reject });
53	        }).then(() => api(originalRequest));
54	      }
55	
56	      originalRequest._retry = true;
57	      isRefreshing = true;
58	
59	      try {
60	        await api.post('/auth/refresh');
61	        processQueue(null);
62	        return api(originalRequest);
63	      } catch (refreshError) {
64	        processQueue(refreshError);
65	        window.location.href = '/login';
66	        return Promise.reject(refreshError);
67	      } finally {
68	        isRefreshing = false;
69	      }
70	    }
71	
72	    return Promise.reject(error);
73	  }
74	);
75	
76	export default api;
77	
