1	package service
2	
3	// ExperimentComponent defines a registered UI component that supports A/B
4	// testing. Every experiment name must match an entry here, and variant names
5	// must be drawn from the component's allowed set.
6	type ExperimentComponent struct {
7		// Description is a human-readable summary shown in the admin UI.
8		Description string
9		// AllowedVariants maps variant name → short description.
10		// The map must contain at least two entries (control + test).
11		AllowedVariants map[string]string
12	}
13	
14	// ExperimentRegistry maps experiment names to the UI components they control.
15	// Adding a new A/B-testable component requires registering it here AND
16	// implementing the corresponding frontend branch.
17	var ExperimentRegistry = map[string]ExperimentComponent{
18		"catalog_layout": {
19			Description: "Controls the collectible catalog grid layout (CatalogPage.tsx)",
20			AllowedVariants: map[string]string{
21				"grid": "Multi-column responsive grid (default)",
22				"list": "Single-column list layout",
23			},
24		},
25		"checkout_flow": {
26			Description: "Controls the order checkout experience (OrderPage.tsx)",
27			AllowedVariants: map[string]string{
28				"standard": "Current multi-step checkout (default)",
29				"express":  "Single-page express checkout",
30			},
31		},
32		"search_ranking": {
33			Description: "Controls the collectible search/sort algorithm (CatalogPage.tsx)",
34			AllowedVariants: map[string]string{
35				"relevance": "Relevance-based ranking (default)",
36				"popular":   "Popularity-weighted ranking",
37			},
38		},
39	}
40	
41	// ValidateExperiment checks that the experiment name and both variant names
42	// are present in the registry. Returns an empty string on success, or a
43	// human-readable error message on failure.
44	func ValidateExperiment(name, controlVariant, testVariant string) string {
45		comp, ok := ExperimentRegistry[name]
46		if !ok {
47			allowed := make([]string, 0, len(ExperimentRegistry))
48			for k := range ExperimentRegistry {
49				allowed = append(allowed, k)
50			}
51			return "unknown experiment name '" + name + "'; registered experiments: " + joinStrings(allowed)
52		}
53	
54		if _, ok := comp.AllowedVariants[controlVariant]; !ok {
55			return "control variant '" + controlVariant + "' is not registered for experiment '" + name + "'; allowed: " + joinStrings(variantKeys(comp))
56		}
57		if _, ok := comp.AllowedVariants[testVariant]; !ok {
58			return "test variant '" + testVariant + "' is not registered for experiment '" + name + "'; allowed: " + joinStrings(variantKeys(comp))
59		}
60		if controlVariant == testVariant {
61			return "control and test variants must be different"
62		}
63		return ""
64	}
65	
66	func variantKeys(c ExperimentComponent) []string {
67		keys := make([]string, 0, len(c.AllowedVariants))
68		for k := range c.AllowedVariants {
69			keys = append(keys, k)
70		}
71		return keys
72	}
73	
74	func joinStrings(ss []string) string {
75		if len(ss) == 0 {
76			return "(none)"
77		}
78		out := ss[0]
79		for _, s := range ss[1:] {
80			out += ", " + s
81		}
82		return out
83	}
84	
