92		// 10 requests per 15 minutes per IP
93		return NewRateLimiter(RateLimiterConfig{
94			Rate:  rate.Every(90 * time.Second), // ~10 per 15 min
95			Burst: 10,
96			KeyFn: func(c echo.Context) string { return "login:" + c.RealIP() },
97		})
