41	// ValidateExperiment checks that the experiment name and both variant names
42	// are present in the registry. Returns an empty string on success, or a
43	// human-readable error message on failure.
44	func ValidateExperiment(name, controlVariant, testVariant string) string {
45		comp, ok := ExperimentRegistry[name]
46		if !ok {
47			allowed := make([]string, 0, len(ExperimentRegistry))
48			for k := range ExperimentRegistry {
49				allowed = append(allowed, k)
50			}
51			return "unknown experiment name '" + name + "'; registered experiments: " + joinStrings(allowed)
52		}
53	
54		if _, ok := comp.AllowedVariants[controlVariant]; !ok {
55			return "control variant '" + controlVariant + "' is not registered for experiment '" + name + "'; allowed: " + joinStrings(variantKeys(comp))
56		}
57		if _, ok := comp.AllowedVariants[testVariant]; !ok {
58			return "test variant '" + testVariant + "' is not registered for experiment '" + name + "'; allowed: " + joinStrings(variantKeys(comp))
59		}
60		if controlVariant == testVariant {
61			return "control and test variants must be different"
62		}
63		return ""
64	}
65	
66	func variantKeys(c ExperimentComponent) []string {
67		keys := make([]string, 0, len(c.AllowedVariants))
68		for k := range c.AllowedVariants {
69			keys = append(keys, k)
70		}
71		return keys
72	}
73	
74	func joinStrings(ss []string) string {
75		if len(ss) == 0 {
76			return "(none)"
77		}
78		out := ss[0]
79		for _, s := range ss[1:] {
80			out += ", " + s
81		}
82		return out
