9	// FNV-1a 32-bit — must match Go's hash/fnv New32a exactly.
10	// This is a cross-language contract: kept in-test because there is no JS
11	// production counterpart (the backend owns variant assignment). The test
12	// verifies the algorithm matches Go output for known vectors.
13	function fnv32a(buf) {
14	  const FNV_PRIME = 0x01000193;
15	  let h = 0x811C9DC5;
16	  for (let i = 0; i < buf.length; i++) {
17	    h ^= buf[i];
18	    h = Math.imul(h, FNV_PRIME) >>> 0;
19	  }
20	  return h >>> 0;
21	}
22	
23	function assignVariant(userId, testName, trafficPct) {
24	  const data = new TextEncoder().encode(userId + testName);
25	  return (fnv32a(data) % 100) < trafficPct ? 'test' : 'control';
