246	func (s *AuthService) Logout(ctx context.Context, userID uuid.UUID) []*http.Cookie {
247		_ = s.userStore.RevokeAllUserTokens(ctx, userID)
248		return []*http.Cookie{
249			{Name: "access_token", Value: "", Path: "/", MaxAge: -1, HttpOnly: true},
250			{Name: "refresh_token", Value: "", Path: "/api/auth", MaxAge: -1, HttpOnly: true},
251			{Name: "csrf_token", Value: "", Path: "/", MaxAge: -1},
252		}
253	}
254	
255	func (s *AuthService) generateAccessToken(userID string, roles []string) (string, error) {
256		claims := &middleware.UserClaims{
257			UserID: userID,
258			Roles:  roles,
259			RegisteredClaims: jwt.RegisteredClaims{
260				ExpiresAt: jwt.NewNumericDate(time.Now().Add(15 * time.Minute)),
261				IssuedAt:  jwt.NewNumericDate(time.Now()),
262				Issuer:    "ledgermint",
263			},
264		}
265		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
266		return token.SignedString(s.signingKey)
267	}
