115	func (s *NotificationService) Retry(ctx context.Context, id, userID uuid.UUID) error {
116		notif, err := s.notifStore.GetByID(ctx, id)
117		if err != nil {
118			return err
119		}
120		if notif == nil {
121			return dto.ErrNotFound
122		}
123		if notif.UserID != userID {
124			return dto.ErrForbidden
125		}
126		if notif.Status != "failed" && notif.Status != "permanently_failed" {
127			return fmt.Errorf("%w: notification is not in a failed state", dto.ErrValidation)
128		}
129		// Manual retry resets to pending so the worker picks it up on the next tick.
130		return s.notifStore.ResetToPending(ctx, id)
131	}
