138		// Default to all_events for backward compatibility when no mode is provided.
139		if subscriptionMode == "" {
140			subscriptionMode = "all_events"
141		}
142		data, err := json.Marshal(prefs)
143		if err != nil {
144			return fmt.Errorf("marshal preferences: %w", err)
145		}
146		return s.notifStore.UpsertPreferences(ctx, userID, data, subscriptionMode)
147	}
