202	func (s *OrderService) ApproveRefund(ctx context.Context, orderID uuid.UUID, actorID uuid.UUID, reason string) (*model.Order, error) {
203		order, err := s.orderStore.GetByID(ctx, orderID)
204		if err != nil {
205			return nil, err
206		}
207		if order == nil {
208			return nil, dto.ErrNotFound
209		}
