218			return nil, fmt.Errorf("%w: refunds can only be approved on completed or cancelled orders", dto.ErrValidation)
219		}
220	
221		// Emit analytics event after successful refund approval
222		s.emitEvent(ctx, &actorID, "refund_approved", &order.CollectibleID)
223	
224		// Send notification to the buyer
225		s.sendRefundNotification(ctx, order, reason)
226	
227		return order, nil
228	}
