30	// Bootstrap creates the first administrator account. It only works when no
31	// admin user exists — once an admin has been created this endpoint returns 409.
32	func (h *SetupHandler) Bootstrap(c echo.Context) error {
33		exists, err := h.userStore.AdminExists(c.Request().Context())
34		if err != nil {
35			return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "internal server error")
36		}
37		if exists {
38			return errorResponse(c, http.StatusConflict, dto.CodeConflict, "setup already complete: an administrator account exists")
39		}
40	
41		var req dto.BootstrapAdminRequest
42		if err := bindAndValidate(c, &req); err != nil {
43			return err
44		}
45	
46		hash, err := crypto.HashPassword(req.Password)
47		if err != nil {
48			return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "internal server error")
49		}
50	
51		user := &model.User{
52			Username:     req.Username,
53			PasswordHash: hash,
54			DisplayName:  req.DisplayName,
55		}
56	
57		if err := h.userStore.Create(c.Request().Context(), user); err != nil {
58			return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to create admin user")
59		}
60	
61		// The first admin grants itself the administrator role.
62		if err := h.userStore.AddRole(c.Request().Context(), user.ID, "administrator", user.ID); err != nil {
63			return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to assign administrator role")
64		}
65	
66		return c.JSON(http.StatusCreated, map[string]string{
67			"status":  "ok",
68			"user_id": user.ID.String(),
69			"message": "Administrator account created. You may now log in.",
70		})
