15	type ABTestService struct {
16		analyticsStore *store.AnalyticsStore
17	}
18	
19	func NewABTestService(as *store.AnalyticsStore) *ABTestService {
20		return &ABTestService{analyticsStore: as}
21	}
22	
23	func (s *ABTestService) Create(ctx context.Context, req dto.CreateABTestRequest, createdBy uuid.UUID) (*model.ABTest, error) {
24		// Enforce experiment-to-component mapping: every experiment must reference
25		// a registered UI component with known variant names.
26		if msg := ValidateExperiment(req.Name, req.ControlVariant, req.TestVariant); msg != "" {
27			return nil, fmt.Errorf("%w: %s", dto.ErrValidation, msg)
28		}
29	
30		startDate, err := parseFlexibleDate(req.StartDate)
31		if err != nil {
32			return nil, fmt.Errorf("%w: invalid start_date format, use RFC3339 or YYYY-MM-DDTHH:MM", dto.ErrValidation)
33		}
34		endDate, err := parseFlexibleDate(req.EndDate)
35		if err != nil {
36			return nil, fmt.Errorf("%w: invalid end_date format, use RFC3339 or YYYY-MM-DDTHH:MM", dto.ErrValidation)
37		}
38	
39		test := &model.ABTest{
40			Name:                 req.Name,
41			Description:          req.Description,
42			Status:               model.ABTestStatusDraft,
43			TrafficPct:           req.TrafficPct,
44			StartDate:            startDate,
45			EndDate:              endDate,
46			ControlVariant:       req.ControlVariant,
47			TestVariant:          req.TestVariant,
48			RollbackThresholdPct: req.RollbackThresholdPct,
49			CreatedBy:            createdBy,
50		}
51	
52		// Auto-start if start date is in the past or now
53		if !startDate.After(time.Now()) {
54			test.Status = model.ABTestStatusRunning
55		}
56	
57		if err := s.analyticsStore.CreateABTest(ctx, test); err != nil {
58			return nil, fmt.Errorf("create A/B test: %w", err)
59		}
60		return test, nil
61	}
62	
63	func (s *ABTestService) GetByID(ctx context.Context, id uuid.UUID) (*model.ABTest, error) {
64		test, err := s.analyticsStore.GetABTestByID(ctx, id)
65		if err != nil {
66			return nil, err
67		}
68		if test == nil {
69			return nil, dto.ErrNotFound
70		}
71		return test, nil
72	}
73	
74	func (s *ABTestService) List(ctx context.Context) ([]model.ABTest, error) {
75		return s.analyticsStore.ListABTests(ctx)
76	}
77	
78	func (s *ABTestService) Update(ctx context.Context, id uuid.UUID, req dto.UpdateABTestRequest) (*model.ABTest, error) {
79		test, err := s.analyticsStore.GetABTestByID(ctx, id)
80		if err != nil {
81			return nil, err
82		}
83		if test == nil {
84			return nil, dto.ErrNotFound
85		}
86		if test.Status != model.ABTestStatusDraft && test.Status != model.ABTestStatusRunning {
87			return nil, fmt.Errorf("%w: cannot update a %s test", dto.ErrValidation, test.Status)
88		}
89	
90		if req.Description != nil {
91			test.Description = *req.Description
92		}
93		if req.TrafficPct != nil {
94			test.TrafficPct = *req.TrafficPct
95		}
96		if req.EndDate != nil {
97			endDate, err := parseFlexibleDate(*req.EndDate)
98			if err != nil {
99				return nil, fmt.Errorf("%w: invalid end_date format", dto.ErrValidation)
100			}
101			test.EndDate = endDate
102		}
103		if req.RollbackThresholdPct != nil {
104			test.RollbackThresholdPct = *req.RollbackThresholdPct
105		}
106	
107		if err := s.analyticsStore.UpdateABTest(ctx, test); err != nil {
108			return nil, fmt.Errorf("update A/B test: %w", err)
109		}
110		return test, nil
111	}
112	
113	func (s *ABTestService) Rollback(ctx context.Context, id uuid.UUID) error {
114		test, err := s.analyticsStore.GetABTestByID(ctx, id)
115		if err != nil {
116			return err
117		}
118		if test == nil {
119			return dto.ErrNotFound
120		}
121		if test.Status != model.ABTestStatusRunning {
122			return fmt.Errorf("%w: test is not running", dto.ErrValidation)
123		}
124		return s.analyticsStore.UpdateABTestStatus(ctx, id, model.ABTestStatusRolledBack)
125	}
126	
127	func (s *ABTestService) Complete(ctx context.Context, id uuid.UUID) error {
128		test, err := s.analyticsStore.GetABTestByID(ctx, id)
129		if err != nil {
130			return err
131		}
132		if test == nil {
133			return dto.ErrNotFound
134		}
135		if test.Status != model.ABTestStatusRunning {
136			return fmt.Errorf("%w: test is not running", dto.ErrValidation)
137		}
138		return s.analyticsStore.UpdateABTestStatus(ctx, id, model.ABTestStatusCompleted)
139	}
140	
141	func (s *ABTestService) GetResults(ctx context.Context, testID uuid.UUID) ([]model.ABTestResult, error) {
142		return s.analyticsStore.GetLatestABTestResults(ctx, testID)
143	}
144	
145	func (s *ABTestService) GetAssignments(ctx context.Context, userID string) ([]dto.ABTestAssignment, error) {
146		tests, err := s.analyticsStore.ListRunningABTests(ctx)
147		if err != nil {
148			return nil, err
149		}
150	
151		assignments := make([]dto.ABTestAssignment, 0, len(tests))
152		for _, test := range tests {
153			variant := AssignVariant(userID, test.Name, test.TrafficPct)
154			variantName := test.ControlVariant
155			if variant == "test" {
156				variantName = test.TestVariant
157			}
158			assignments = append(assignments, dto.ABTestAssignment{
159				TestName: test.Name,
160				Variant:  variantName,
161			})
162		}
163		return assignments, nil
164	}
165	
166	// parseFlexibleDate accepts datetime-local (2006-01-02T15:04), RFC3339, and US format.
167	func parseFlexibleDate(s string) (time.Time, error) {
168		formats := []string{
169			"2006-01-02T15:04",       // HTML datetime-local
170			time.RFC3339,             // Standard API format
171			"2006-01-02T15:04:05",   // ISO without timezone
172			"01/02/2006 3:04 PM",    // US human-readable
173		}
174		for _, f := range formats {
175			if t, err := time.Parse(f, s); err == nil {
176				return t, nil
177			}
178		}
179		return time.Time{}, fmt.Errorf("unrecognized date format: %s", s)
180	}
181	
182	// AssignVariant uses deterministic hashing: fnv32(userID + testName) % 100.
183	func AssignVariant(userID, testName string, trafficPct int) string {
184		h := fnv.New32a()
185		h.Write([]byte(userID + testName))
186		bucket := int(h.Sum32() % 100)
187		if bucket < trafficPct {
188			return "test"
189		}
190		return "control"
191	}
