28	func (s *CollectibleService) Create(ctx context.Context, req dto.CreateCollectibleRequest, sellerID uuid.UUID) (*model.Collectible, error) {
29		currency := req.Currency
30		if currency == "" {
31			currency = "USD"
32		}
33	
34		tokenID := req.TokenID
35		chainID := req.ChainID
36		hasToken := tokenID != ""
37		hasChain := chainID != 0
38		if req.ContractAddress != "" {
39			if !hasToken || !hasChain {
40				return nil, fmt.Errorf("%w: contract_address requires chain_id and token_id", dto.ErrValidation)
41			}
42		} else if hasToken || hasChain {
43			// When either identity field is provided, require both.
44			if !hasToken || !hasChain {
45				return nil, fmt.Errorf("%w: chain_id and token_id must both be provided when either is set", dto.ErrValidation)
46			}
47		} else {
48			// Neither provided — generate platform defaults for off-chain items.
49			tokenID = uuid.New().String()
50			chainID = 1
51		}
52	
53		c := &model.Collectible{
54			SellerID:        sellerID,
55			Title:           req.Title,
56			Description:     req.Description,
57			ContractAddress: req.ContractAddress,
58			ChainID:         chainID,
59			TokenID:         tokenID,
60			MetadataURI:     req.MetadataURI,
61			ImageURL:        req.ImageURL,
62			PriceCents:      req.PriceCents,
63			Currency:        currency,
64		}
65	
66		if err := s.collectibleStore.Create(ctx, c); err != nil {
67			if strings.Contains(err.Error(), "idx_collectibles_identity") || strings.Contains(err.Error(), "duplicate key") {
68				return nil, fmt.Errorf("%w: a collectible with this contract_address, chain_id, and token_id already exists", dto.ErrConflict)
69			}
70			return nil, fmt.Errorf("create collectible: %w", err)
71		}
72		s.invalidateCache()
73		return c, nil
74	}
