128	func (s *CollectibleService) List(ctx context.Context, status string, page, pageSize int, viewerRoles []string, userID *uuid.UUID) ([]model.Collectible, int, error) {
129		// Non-admin/compliance users can ONLY see published
130		if !hasAdminOrCompliance(viewerRoles) {
131			status = "published"
132		}
133	
134		cacheKey := fmt.Sprintf("collectibles:%s:%d:%d", status, page, pageSize)
135		if cached, ok := s.cache.Get(cacheKey); ok {
136			result := cached.(*cachedList)
137			return result.items, result.total, nil
138		}
139	
140		items, total, err := s.collectibleStore.List(ctx, status, page, pageSize)
141		if err != nil {
142			return nil, 0, err
143		}
144	
145		s.cache.Set(cacheKey, &cachedList{items: items, total: total}, 30*time.Second)
146	
147		// Emit catalog_view event async with A/B variant tagging
148		if s.analyticsStore != nil {
149			abVariant := resolveABVariant(s.analyticsStore, userID)
150			go func() {
