293	// resolveABVariant builds a comma-separated ab_variant tag for all running tests.
294	// Returns "" if there are no running tests or the user is nil.
295	func resolveABVariant(analyticsStore *store.AnalyticsStore, userID *uuid.UUID) string {
296		if userID == nil || analyticsStore == nil {
297			return ""
298		}
299		tests, _ := analyticsStore.ListRunningABTests(context.Background())
300		if len(tests) == 0 {
301			return ""
302		}
303		parts := make([]string, 0, len(tests))
304		for _, t := range tests {
305			v := AssignVariant(userID.String(), t.Name, t.TrafficPct)
306			variantName := t.ControlVariant
307			if v == "test" {
308				variantName = t.TestVariant
309			}
310			parts = append(parts, t.Name+":"+variantName)
311		}
312		return strings.Join(parts, ",")
313	}
