127	// TransitionStatus with object-level authorization.
128	// Confirm/Process/Complete: only the seller of THIS order.
129	// Cancel: only the buyer or seller of THIS order.
130	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
131		order, err := s.orderStore.GetByID(ctx, orderID)
132		if err != nil {
133			return nil, err
134		}
135		if order == nil {
136			return nil, dto.ErrNotFound
137		}
138	
139		// Object-level authorization
140		switch targetStatus {
141		case model.OrderStatusConfirmed, model.OrderStatusProcessing, model.OrderStatusCompleted:
142			if order.SellerID != actorID {
143				return nil, fmt.Errorf("%w: only the seller of this order can perform this action", dto.ErrForbidden)
144			}
145		case model.OrderStatusCancelled:
146			if order.BuyerID != actorID && order.SellerID != actorID {
147				return nil, fmt.Errorf("%w: only the buyer or seller of this order can cancel it", dto.ErrForbidden)
148			}
149		}
150	
151		if !order.Status.CanTransitionTo(targetStatus) {
152			s.emitEvent(ctx, &actorID, "checkout_failed", &order.CollectibleID)
153			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
154		}
155	
156		if targetStatus == model.OrderStatusCancelled {
157			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
158				s.emitEvent(ctx, &actorID, "checkout_failed", &order.CollectibleID)
159				return nil, fmt.Errorf("cancel order: %w", err)
160			}
161			s.emitEvent(ctx, &actorID, "order_cancelled", &order.CollectibleID)
162		} else {
163			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
164				s.emitEvent(ctx, &actorID, "checkout_failed", &order.CollectibleID)
165				return nil, fmt.Errorf("update status: %w", err)
166			}
167			// Emit transition events so AB tests and funnels track the full order lifecycle.
168			statusEventMap := map[model.OrderStatus]string{
169				model.OrderStatusConfirmed: "order_confirmed",
170				model.OrderStatusCompleted: "order_completed",
171			}
172			if eventType, ok := statusEventMap[targetStatus]; ok {
173				s.emitEvent(ctx, &actorID, eventType, &order.CollectibleID)
174			}
175		}
176	
177		transition := &model.OrderStateTransition{
178			OrderID:    orderID,
179			FromStatus: order.Status,
180			ToStatus:   targetStatus,
181			ActorID:    actorID,
182			Reason:     reason,
183		}
184		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
185			return nil, fmt.Errorf("record transition: %w", err)
186		}
187	
188		// On completion, record an immutable transaction history entry for the
189		// collectible, representing the ownership transfer from seller to buyer.
190		if targetStatus == model.OrderStatusCompleted {
191			s.recordOwnershipTransfer(ctx, order)
192		}
193	
194		s.sendOrderNotification(ctx, order, targetStatus, reason)
195	
196		order.Status = targetStatus
197		return order, nil
198	}
