310	// recordOwnershipTransfer appends an immutable record to collectible_tx_history
311	// when an order completes. The record captures the seller→buyer transfer using
312	// the collectible's on-chain identity. This is best-effort: a failure here does
313	// not roll back the order completion.
314	func (s *OrderService) recordOwnershipTransfer(ctx context.Context, order *model.Order) {
315		collectible, err := s.collectibleStore.GetByID(ctx, order.CollectibleID)
316		if err != nil || collectible == nil {
317			return
318		}
319	
320		fromAddr := collectible.ContractAddress
321		if fromAddr == "" {
322			fromAddr = order.SellerID.String()
323		}
324		toAddr := order.BuyerID.String()
325	
326		txHash := fmt.Sprintf("order:%s", order.ID.String())
327		blockNumber := order.PriceSnapshotCents // deterministic, non-zero value
328	
329		entry := &model.CollectibleTxHistory{
330			CollectibleID: order.CollectibleID,
331			TxHash:        txHash,
332			FromAddress:   fromAddr,
333			ToAddress:     toAddr,
334			BlockNumber:   blockNumber,
335			Timestamp:     time.Now(),
336		}
337	
338		// Best-effort: do not fail the order on tx history write failure.
339		_ = s.collectibleStore.RecordTxHistory(ctx, entry)
340	}
