103	func contains(s, sub string) bool {
104		return len(s) >= len(sub) && containsSubstr(s, sub)
105	}
106	
107	func containsSubstr(s, sub string) bool {
108		for i := 0; i <= len(s)-len(sub); i++ {
109			if s[i:i+len(sub)] == sub {
110				return true
111			}
112		}
113		return false
114	}
