221	// GetCurrentUser returns the user profile and roles for the already-authenticated
222	// user. Used on app init to restore session state after page reload.
223	func (s *AuthService) GetCurrentUser(ctx context.Context, userID uuid.UUID) (*dto.AuthResponse, error) {
224		user, err := s.userStore.GetByID(ctx, userID)
225		if err != nil || user == nil {
226			return nil, dto.ErrUnauthorized
227		}
228		userRoles, err := s.userStore.GetUserRoles(ctx, user.ID)
229		if err != nil {
230			return nil, fmt.Errorf("get roles: %w", err)
231		}
232		roleNames := make([]string, len(userRoles))
233		for i, r := range userRoles {
234			roleNames[i] = r.RoleName
235		}
236		return &dto.AuthResponse{
237			User: dto.UserResponse{
238				ID: user.ID, Username: user.Username, DisplayName: user.DisplayName,
239				IsLocked: user.IsLocked,
240				CreatedAt: user.CreatedAt, UpdatedAt: user.UpdatedAt,
241			},
242			Roles: roleNames,
243		}, nil
244	}
