44		if enabled, exists := prefMap[templateSlug]; exists && !enabled {
45			return nil // User opted out
46		}
47	
48		// Filter by subscription mode. Default to all_events for backward compatibility.
49		mode := prefs.SubscriptionMode
50		if mode == "" {
51			mode = "all_events"
52		}
53		if mode == "status_only" && !statusOnlySlugs[templateSlug] {
54			return nil // Event excluded by subscription mode
55		}
56	
57		template, err := s.notifStore.GetTemplateBySlug(ctx, templateSlug)
58		if err != nil {
59			return fmt.Errorf("get template: %w", err)
60		}
61		if template == nil {
62			return fmt.Errorf("template not found: %s", templateSlug)
63		}
64	
65		// Render template
66		var params map[string]string
67		if err := json.Unmarshal(paramsJSON, &params); err != nil {
68			params = make(map[string]string)
69		}
70	
71		title := renderTemplate(template.TitleTemplate, params)
72		body := renderTemplate(template.BodyTemplate, params)
73	
74		notif := &model.Notification{
75			UserID:        userID,
76			TemplateID:    template.ID,
77			Params:        paramsJSON,
78			RenderedTitle: title,
79			RenderedBody:  body,
80			Status:        "pending",
81		}
82	
83		if err := s.notifStore.Create(ctx, notif); err != nil {
84			return fmt.Errorf("create notification: %w", err)
85		}
86		return nil
87	}
