func TestOrderTransition_CancelByBuyerAllowed(t *testing.T) {
	if err := orderTransitionAuth(testOrder, model.OrderStatusCancelled, buyer); err != nil {
		t.Fatalf("buyer should cancel: %v", err)
	}
