1	package middleware
2	
3	import (
4		"crypto/rand"
5		"encoding/hex"
6		"net/http"
7	
8		"github.com/labstack/echo/v4"
9		"github.com/ledgermint/platform/internal/dto"
10	)
11	
12	func CSRF() echo.MiddlewareFunc {
13		return func(next echo.HandlerFunc) echo.HandlerFunc {
14			return func(c echo.Context) error {
15				// Skip for safe methods
16				if c.Request().Method == http.MethodGet ||
17					c.Request().Method == http.MethodHead ||
18					c.Request().Method == http.MethodOptions {
19					return next(c)
20				}
21	
22				// Skip CSRF for pre-session endpoints where no cookie exists yet.
23				// - /api/auth/login: pre-auth, no cookies.
24				// - /api/setup/admin: one-time bootstrap before any user session
25				//   exists. This endpoint self-disables after the first admin is
26				//   created, so the exemption window is minimal.
27				// Refresh is protected: the client has a csrf_token cookie from login.
28				path := c.Request().URL.Path
29				if path == "/api/auth/login" || path == "/api/setup/admin" {
30					return next(c)
31				}
32	
33				cookie, err := c.Cookie("csrf_token")
34				if err != nil {
35					return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
36						Error: dto.ErrorDetail{
37							Code:      dto.CodeForbidden,
38							Message:   "missing CSRF cookie",
39							RequestID: GetRequestID(c),
40						},
41					})
42				}
43	
44				header := c.Request().Header.Get("X-CSRF-Token")
45				if header == "" || header != cookie.Value {
46					return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
47						Error: dto.ErrorDetail{
48							Code:      dto.CodeForbidden,
49							Message:   "CSRF token mismatch",
50							RequestID: GetRequestID(c),
51						},
52					})
53				}
54	
55				return next(c)
56			}
57		}
58	}
59	
60	func GenerateCSRFToken() (string, error) {
61		b := make([]byte, 32)
62		if _, err := rand.Read(b); err != nil {
63			return "", err
64		}
65		return hex.EncodeToString(b), nil
66	}
67	
68	func SetCSRFCookie(c echo.Context, token string) {
69		c.SetCookie(&http.Cookie{
70			Name:     "csrf_token",
71			Value:    token,
72			Path:     "/",
73			HttpOnly: false, // Must be readable by JS
74			Secure:   false, // LAN - no TLS
75			SameSite: http.SameSiteStrictMode,
76		})
77	}
