21	function validateExperiment(name, controlVariant, testVariant) {
22	  const comp = EXPERIMENT_REGISTRY[name];
23	  if (!comp) {
24	    const allowed = Object.keys(EXPERIMENT_REGISTRY).join(', ') || '(none)';
25	    return `unknown experiment name '${name}'; registered experiments: ${allowed}`;
