27	  if (!comp.allowedVariants.has(controlVariant)) {
28	    return `control variant '${controlVariant}' is not registered for experiment '${name}'`;
29	  }
30	  if (!comp.allowedVariants.has(testVariant)) {
31	    return `test variant '${testVariant}' is not registered for experiment '${name}'`;
